import com.tuling.common.base.entity.JsonResult;
import java.util.Map;
import com.tuling.common.redis.template.RedisRepository;
import com.tuling.dto.user.OsUserDto;
import com.tuling.lowcodeform.feign.OsUserClient;
import com.tuling.common.utils.SpringUtil;
import java.util.HashMap;
import java.util.Map;

//对每一行进行判断处理
JsonResult handRow(Map<String,Object> data){
    //return JsonResult.fail("出错原因");
    return JsonResult.Success();
}

//对读取的数据进行处理
JsonResult beforeInsert(List<Map<String,Object>> data){
    RedisRepository redisRepository = SpringUtil.getBean(RedisRepository.class);
    OsUserClient userClient = SpringUtil.getBean(OsUserClient.class);
    // return JsonResult.fail("出错原因");
    Map<String,String> errorMap = new HashMap();
    for(int i=0;i<data.size();i++){
        Map<String,Object> map = data.get(i);
            String userNo = String.valueOf(map.get("person"));
            String nameTXT = String.valueOf(map.get("nameTXT"));
            OsUserDto osUserDto = (OsUserDto) redisRepository.get("OSUSERDTO"+ userNo);
            if(osUserDto==null){
                osUserDto = userClient.getByUserNo(userNo);
                if(osUserDto!=null){
                    redisRepository.set("OSUSERDTO"+ userNo);
                }
            }
            if(osUserDto==null||!nameTXT.equals(osUserDto.getFullName())){
                errorMap.put("excel_"+(i+2),"姓名和工号不匹配");

            }
    }
    if(errorMap.size()>0){
        return JsonResult.getFailResult(errorMap,"");
    }
    return JsonResult.Success();
}

