//对每一行进行判断处理
JsonResult handRow(Map<String,Object> data){
    String startDate = String.valueOf(data.get("startDate"));
     String endDate = String.valueOf(data.get("endDate"));
    if(StringUtils.isNotEmpty(startDate)&&StringUtils.isNotEmpty(endDate)){
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");

        try {
           Date endDateD = sdf.parse(endDate);
           Date startDateD = sdf.parse(startDate);

            // 比较日期
            if (endDateD.before(startDateD)) {
              return JsonResult.Fail().setMessage("发放结束日期不能早于开始日期");
            } 
       } catch (ParseException e) {
            e.printStackTrace();
        }

    }
    return JsonResult.Success();
}

